import{V as e,et as t,mt as n,tt as r}from"./chunks/framework.DpI_zlPE.js";var i=JSON.parse(`{"title":"固态","description":"","frontmatter":{},"headers":[],"relativePath":"ccc/电脑/固态.md","filePath":"ccc/电脑/固态.md"}`),a={name:`ccc/电脑/固态.md`};function o(e,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[r(`<h1 id="固态" tabindex="-1">固态 <a class="header-anchor" href="#固态" aria-label="Permalink to “固态”">​</a></h1><p>更新于2023.4.4</p><p>固态跑分只说明爆发力，都有模拟SLC，参考价值非常有限。</p><p>挖过奇亚币的都知道，长江存储的原厂颗粒遥遥领先，不是倭国躬匠恺侠白片冒充原厂颗粒，以破坏客户数据为使命的闪迪，人为降低闪存寿命的三棒能碰瓷的。</p><p>致态5000，7100性能基本基本看作一个水平，无非7100跑分更好看，爆发性能更强。</p><p>致态PC005，7000pro这种带外置缓存的性能更高，满速容量60%。就算掉速了，缓外写入还是有2g左右。无外置缓存固态一般都是剩余容量20%的空间模拟SLC，写入超过开始掉速，1.5g左右，如果盘很脏，很快就掉到700m。</p><p><strong>系统盘最好买带外置缓存固态硬盘，无论原厂副厂。</strong>windows系统盘就算啥也不干，光临时文件就是大量写入。</p><blockquote><p>只要定期擦洗，程序盘用无缓存副厂盘，应该也是够用的。 不定期擦洗，程序盘买副厂盘最好带外置缓存。</p><p>关于擦洗请见后文-改善副厂无缓存固态的使用体验。</p></blockquote><h3 id="改善副厂无缓存固态的使用体验" tabindex="-1">改善副厂无缓存固态的使用体验 <a class="header-anchor" href="#改善副厂无缓存固态的使用体验" aria-label="Permalink to “改善副厂无缓存固态的使用体验”">​</a></h3><p>固态硬盘健康度下降是坏块被备用块替换的正常现象，不为0就没事，但是主控读取时才知道好坏，超出纠错上限就会有“文件静默损坏”。</p><p>用于存储会有大量冷数据处于如好状态，出现静默损坏的概率大增。务必做好定期数据擦洗校验：</p><ul><li><p>win11格式化ReFS，<a href="https://link.zhihu.com/?target=https%3A//learn.microsoft.com/zh-cn/windows-server/storage/refs/integrity-streams" target="_blank" rel="noreferrer">开启可选功能-完整性流</a>，配置任务计划程序Microsoft\\Windows\\数据完整性扫描（默认每四周，酌情减少间隔），或定期手动校验。通过校验提前完成纠错和冷数据预热。</p></li><li><p>NTFS定期用7zip对整个磁盘计算CRC32也能为冷数据纠错预热，但毕竟没有校验。</p></li></ul><h3 id="固态硬盘的外置缓存" tabindex="-1">固态硬盘的外置缓存 <a class="header-anchor" href="#固态硬盘的外置缓存" aria-label="Permalink to “固态硬盘的外置缓存”">​</a></h3><p>可以一力降十会，FTL表，Bitmap表会更宽裕，GC触发更少，GC算法效率好得多，理论寿命更长。<strong>带外置缓存的固态最重要的是更低的售后期望。</strong></p><h3 id="副厂固态硬盘" tabindex="-1">副厂固态硬盘 <a class="header-anchor" href="#副厂固态硬盘" aria-label="Permalink to “副厂固态硬盘”">​</a></h3><p>正片颗粒暴毙概率很小。白片颗粒有较小概率暴毙，而拆机片，黑片，暴毙概率很大。</p><p>只要不是颗粒暴毙，即使出现掉盘，健康度下降，一般只要不误操作，并做好擦洗，数据完全损失概率较小。</p><p>如梵想，移速，海康，七彩虹，朗科，达墨，金士顿，acer宏碁等贴牌，代工厂自有品牌如阿斯加特，光威，金百达，江波龙雷克沙。</p><p>除了白片，还会混有拆机片，黑片。存在送测或前几批用好一点的颗粒，之后图穷匕见的现象。这几个牌子我估计就阿斯加特跟雷克沙因为定位相对高一点，可能会好一点。</p><blockquote><p>截止23年8月，说自己是长江颗粒的好赖是白片。</p></blockquote><p>副厂盘除了文件静默损坏概率大，还有可能读冷数据需要纠错，导致速度变慢，系统盘会导致系统响应很慢。</p><p>详细了解请参考<a href="https://chnhi.github.io/lxzdy/ccc/%E6%97%A0%E7%BA%BF%E8%B7%AF%E7%94%B1%E5%99%A8/%E9%BB%91%E7%BE%A4%E6%99%96zfs.html" target="_blank" rel="noreferrer">【switch·路由器·手机·NAS 】-【truenas】</a>。</p><h2 id="离线移动固态硬盘不能用于备份" tabindex="-1">离线移动固态硬盘不能用于备份 <a class="header-anchor" href="#离线移动固态硬盘不能用于备份" aria-label="Permalink to “离线移动固态硬盘不能用于备份”">​</a></h2><p>固态硬盘的特性来看，明显离线移动固态硬盘只能作为大号u盘，进行临时性的文件转移，用作备份是相当危险的。更不要说固态硬盘需要进行GC，TRIM等操作。</p><p>我认为，合理的用于存储的固态硬盘盒必须是配电池的在线式简易nas。当下的产品只能用于诸如wintogo等用途。</p><p>因此有一个算一个，所有的移动固态硬盘，移动固态硬盘盒产品都是对用户数据极端不负责任。三星，WD闪迪，铠侠热衷于推出此类产品，巴不得用户遇到数据丢失的灾难。</p><p>已经爆发血的教训：<a href="./www.ithome.com/0/711/776.htm.html">WD闪迪Extreme移动固态硬盘大面积故障</a>，更令人震惊的是，借着解决问题为由，推送新固件扩大战果，可以说WD闪迪，三星和铠侠三家劣迹企业中WD闪迪最不忘初心，以破坏用户数据为己任。</p><h3 id="legacy" tabindex="-1">Legacy： <a class="header-anchor" href="#legacy" aria-label="Permalink to “Legacy：”">​</a></h3><p>  只有长时间重度负载或者作为阵列缓存才需要考虑旗舰固态。玩游戏或者日常正常使用的没必要考虑。作为缓存，拆机傲腾16g，32g分别是50块，120块左右，买两块组raid也是不错的选择。</p><ul><li><strong>三星970 pro</strong></li></ul><blockquote><p>  作为缓存或者长时间重度读写负载不掉速，MLC颗粒。工包sm961，pm961大概率不是新的。如果没货的话可以考虑970evo plus，缓外写入也有1.65g/s，便宜多了。pcie4.0方案的三星980pro，缓外写入前300g 1.85g/s，之后掉到1.65g/s。</p><p>  三星980满盘速度比970 evo plus还慢，甚至不如sn550，极度不推荐。</p></blockquote><p>  pcie4.0方案还有群联e18的影驰 名人堂hof EXTREME，wd SN850靠全盘模拟SLC撑场面，包括三星随着空间变小，表现相对pcie3.0的产品没有显著提升，酌情考虑。wd SN850 缓外前500g 2.7g/s，之后1.25g/s。群联e18也是全盘动态slc，搭载e16的hof pro应该要清仓了，可以抄底，缺点是28nm制程主控。</p><table tabindex="0"><thead><tr><th style="text-align:center;"></th><th style="text-align:center;">主控</th><th style="text-align:center;">颗粒</th><th style="text-align:center;">缓存</th><th style="text-align:center;">接口速率</th></tr></thead><tbody><tr><td style="text-align:center;">三星980</td><td style="text-align:center;">Pablo</td><td style="text-align:center;">三星136层TLC</td><td style="text-align:center;">无</td><td style="text-align:center;">4.0x4</td></tr><tr><td style="text-align:center;">三星980 pro</td><td style="text-align:center;">Elpis</td><td style="text-align:center;">三星136层TLC</td><td style="text-align:center;">每500g配500m</td><td style="text-align:center;">4.0x4</td></tr><tr><td style="text-align:center;">三星970evo plus</td><td style="text-align:center;">Phoenix</td><td style="text-align:center;">三星96层TLC</td><td style="text-align:center;">每500g配500m</td><td style="text-align:center;">3.0x4</td></tr><tr><td style="text-align:center;">影驰 hof EXTREME</td><td style="text-align:center;">PS5018-E18</td><td style="text-align:center;">东芝</td><td style="text-align:center;"></td><td style="text-align:center;">4.0x4</td></tr><tr><td style="text-align:center;">影驰 hof Pro</td><td style="text-align:center;">PS5016-E16</td><td style="text-align:center;">东芝</td><td style="text-align:center;"></td><td style="text-align:center;">4.0x4</td></tr></tbody></table>`,33)]])}var s=e(a,[[`render`,o]]);export{i as __pageData,s as default};